import {useEffect, useState} from "react";
import type {IList} from "@lmb-it/kitsconcerto-types";


export const listToObject = (list:any[], labelKey:string, valueKey:string)=>{
    if (Array.isArray(list)) {
        if (list.some(o => typeof o == "string")) {
            return list.map(o => {
                return {
                    [labelKey]: o,
                    [valueKey]: o
                }
            });
        }
        if (list.some(o => !(labelKey in o && valueKey in o))) {
            throw Error("Tags component: In List prop you should pass either strings or object with keys match your dataLabelKey and dataIdKey or label and id");
        }
        return list;
    }

    return [];
}

export const selectHelper=(customProps:any, field:any, value:any, listFetcher:any) =>{
    const {
        list,
        dataLabelKey = "label",
        dataIdKey = "id",
    } = customProps;

    const [isLoading, setIsLoading] = useState<boolean>(false);
    const [filteredOptions, setFilteredOptions] = useState<IList[]>([]);

    const getList = () => {
        if (Array.isArray(list)) {
            return listToObject(list, dataLabelKey, dataIdKey);
        }
        if (typeof list === "function") {
            return listToObject(list(value), dataLabelKey, dataIdKey);
        }

        return [];
    };

    useEffect(() => {
        const _list = getList();

        if (JSON.stringify(_list) !== JSON.stringify(filteredOptions)) {
            setFilteredOptions(_list);
        }
    }, []);

    const removeDuplicates = (list: string[]) => {
        if (Array.isArray(field.value)) {
            return list.filter((val) => !field.value.includes(val));
        }

        return list;
    };

    const onSearchValue = (dataItem:any) => {
        if (listFetcher) {
            setIsLoading(true);
            listFetcher(dataItem)
                .then((res:any) => {
                    let newList: IList[] = [];

                    if (res.length > 0) {
                        newList = newList.concat(removeDuplicates(res));
                    }

                    setFilteredOptions(newList);
                })
                .finally(() => {
                    setIsLoading(false);
                });
        }
    };

    return {
        isLoading,
        filteredOptions,
        onSearchValue,
    };
}


export function ClHelper({
                             isChecked,
                             isInvalid,
                             isDisabled,
                             inputSize,
                         }: {
    isChecked: boolean;
    isInvalid: boolean;
    isDisabled: boolean;
    inputSize: string;
}): string {
    const classes = ["check-input"];

    if (isChecked) {
        classes.push("p-checked");
    }

    // p-invalid and size classes are now applied by KitsContainer's inner wrapper Flex,
    // so they're not duplicated here. Individual elements that use `attached` mode
    // (bypassing the container) should handle these themselves if needed.

    if (isDisabled) {
        classes.push("p-disable");
    }

    return classes.join(" ");
}
